import itertools

class Brick:
    def __init__(self, id):
        self.id = id
        self.connections = []

    def connect(self, brick):
        self.connections.append(brick)

class BrickCombination:
    def __init__(self, bricks):
        self.bricks = bricks

    def is_trivial(self):
        for brick in self.bricks:
            if len(brick.connections) > 2:
                return False
        return True

    def complexity(self):
        complexity = 0
        for brick in self.bricks:
            complexity += len(brick.connections)
        return complexity

def generate_combinations(bricks):
    combinations = []
    for p in itertools.permutations(bricks):
        combination = BrickCombination([Brick(i) for i in range(len(bricks))])
        for i in range(len(p) - 1):
            combination.bricks[i].connect(combination.bricks[i + 1])
        combinations.append(combination)
    return combinations

