    bricks = [i for i in range(6)]
    combinations = generate_combinations(bricks)
    trivial_count = 0
    complicated_count = 0
    for combination in combinations:
        if combination.is_trivial():
            trivial_count += 1
        else:
            complicated_count += 1
            print(f"Complicated combination: {combination.complexity()}")
    print(f"Total combinations: {len(combinations)}")
    print(f"Trivial combinations: {trivial_count}")
    print(f"Complicated combinations: {complicated_count}")

if __name__ == "__main__":
    main()

