    def __init__(self, bricks):
        self.bricks = bricks

    def __repr__(self):
        return f"Combination({self.bricks})"

    def is_trivial(self):
        # A combination is trivial if all bricks are stacked on top of each other
        return all(brick.width == self.bricks[0].width for brick in self.bricks)

    def complexity(self):
        # A combination's complexity is the number of unique brick positions
        positions = set()
        for brick in self.bricks:
            positions.add((brick.width, brick.height))
        return len(positions)

