    combinations = []
    for permutation in itertools.permutations(bricks):
        combination = Combination(permutation)
        combinations.append(combination)
    return combinations

def classify_combinations(combinations):
    classified_combinations = {"trivial": [], "complicated": []}
    for combination in combinations:
        if combination.is_trivial():
            classified_combinations["trivial"].append(combination)
        else:
            classified_combinations["complicated"].append(combination)
    return classified_combinations

